const config = $('Config').first()?.json ?? {};
const results = $input.first().json?.results ?? [];
return results.map(r => ({
  json: {
    ...config,
    source: 'BOAMP',
    external_id: r.idweb ?? r.id ?? '',
    title: r.objet ?? 'Sans titre',
    raw_data: r,
    body: (r.objet ?? '') + ' ' + (r.descripteur_libelle?.join(' ') ?? '') + ' ' + (r.type_marche_facette?.join(' ') ?? '')
  }
}));

