const resp = $input.first().json;
const content = resp.choices?.[0]?.message?.content ?? resp.message?.content ?? '{}';
let parsed = {};
try { parsed = JSON.parse(content.replace(/```json?/g,'').replace(/```/g,'').trim()); } catch(e) { parsed = { pertinence: 50 }; }
const allNorm = $('Normalize Tender Data').all();
const idx = $itemIndex ?? 0;
const opp = allNorm[idx]?.json ?? allNorm[0]?.json ?? {};
const score = Math.min(100, Math.max(0, parsed.pertinence ?? 50));
const threshold = opp.SCORE_THRESHOLD ?? 75;
return { json: { ...opp, ...parsed, score, status: score >= threshold ? 'notified' : 'archived' } };
